import ShopActionsTypes from './shopt.types';

const INITIAL_STATE = {
	collections: null,
	isFetching: false,
};

const shopReducer = (state = INITIAL_STATE, action) => {
	switch (action.type) {
		case ShopActionsTypes.UPDATE_COLLECTIONS:
			return {
				...state,
				collections: action.payload,
			};
		default:
			return state;
	}
};

export default shopReducer;
